sql:
SELECT p.player_name
FROM player_career_stats pcs
INNER JOIN players p ON pcs.player_id = p.player_id
WHERE pcs.win_percentage > (
    SELECT AVG(win_percentage) FROM player_career_stats
);

SELECT AVG(points_per_game) AS average_points_per_game
FROM player_career_stats
WHERE games_played > 50;

external_knowledge:
- "standout players" refers to players with a career length longer than 5 years;
- "two decades of points per game" represents a points per game average above 20;
- "elite and near-elite divisions" are NCAA I and NCAA II;
- "total achievements" refer to the total number of awards received by the player;
- "scoring prowess" is represented by the points per game metric.

sql:
SELECT player_id, player_name, school_id
FROM player_career_stats
WHERE points_per_game > (SELECT AVG(points_per_game) FROM player_career_stats);

SELECT player_name, points_per_game 
FROM player_career_stats
WHERE points_per_game = (SELECT MAX(points_per_game) FROM player_career_stats);

SELECT AVG(players.height) AS avg_height
FROM players
INNER JOIN awards ON players.player_id = awards.player_id;

SELECT AVG(pcs.games_played) AS AverageGamesPlayed
FROM player_career_stats pcs
JOIN awards a ON pcs.player_id = a.player_id;

external_knowledge:
- "notable participation" implies playing more than 20 games;
- "cumulative distribution" refers to the statistical measure `CUME_DIST()` which ranks players based on their points per game within their respective conferences;
- "institutions" refers to schools;
- "leagues" refers to conferences.

sql:
SELECT player_name, height, weight, DENSE_RANK() OVER (ORDER BY height DESC) AS height_rank
FROM players
WHERE weight > 200;

external_knowledge:
- 'Older' players refer to those who have participated in more than half of their games with a winning record;
- The 'top scorer' in this context is the player with the highest total points per game across all players filtered by the NCAA II division and their win-to-game ratio;
- 'Award-winning players' are those who have been recognized with at least one award.
